import{c as e,Q as n,j as a,m as o}from"./chunks/framework.BPKcPtvA.js";const c=JSON.parse('{"title":"Customer Billing","description":"","frontmatter":{},"headers":[],"relativePath":"guide/admin/finance/customer-billing.md","filePath":"guide/admin/finance/customer-billing.md","lastUpdated":1778912818000}'),r={name:"guide/admin/finance/customer-billing.md"};function i(s,t,l,d,u,g){return n(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="customer-billing" tabindex="-1">Customer Billing <a class="header-anchor" href="#customer-billing" aria-label="Permalink to &quot;Customer Billing&quot;">​</a></h1><p>The <strong>Customer Billing</strong> page is the full billing workspace for one customer. It is where you issue invoices, record payments, add credits, configure plan and tax, and override billing for individual non-prod tenants.</p><p>The page has two tabs: <strong>Overview</strong> and <strong>Billing Setup</strong>.</p><h2 id="header" tabindex="-1">Header <a class="header-anchor" href="#header" aria-label="Permalink to &quot;Header&quot;">​</a></h2><ul><li>Back link to <a href="./customers">Finance Customers</a>.</li><li>Customer name, status badge.</li><li>Quick billing details — Plan, Plan Version, Billing Contact Email, Timezone.</li><li><strong>Upgrade banner</strong> — if the customer is on an outdated plan version, a warning banner shows with an <strong>Upgrade to v[N]</strong> button. Upgrade takes effect on the next invoice.</li></ul><h2 id="overview-tab" tabindex="-1">Overview tab <a class="header-anchor" href="#overview-tab" aria-label="Permalink to &quot;Overview tab&quot;">​</a></h2><h3 id="summary-cards" tabindex="-1">Summary cards <a class="header-anchor" href="#summary-cards" aria-label="Permalink to &quot;Summary cards&quot;">​</a></h3><p>Four metric cards at the top, colour-coded:</p><ul><li><strong>Total Invoiced</strong> — sum of all issued invoices.</li><li><strong>Total Paid</strong> — sum of completed payments.</li><li><strong>Outstanding</strong> — unpaid amount. Highlighted danger-coloured if overdue, warning-coloured otherwise.</li><li><strong>Credit Balance</strong> — credits available on the account. Info-coloured if positive.</li></ul><h3 id="action-buttons" tabindex="-1">Action buttons <a class="header-anchor" href="#action-buttons" aria-label="Permalink to &quot;Action buttons&quot;">​</a></h3><ul><li><strong>Issue Invoice</strong> — opens a modal. <ul><li>For period-based plans (monthly / quarterly / annual): pick start (auto-fills to day after the last invoice) and end. The system computes the amount from usage and plan.</li><li>For perpetual plans: enter a fixed amount and an optional description.</li></ul></li><li><strong>Record Payment</strong> — opens a modal. Select invoice, enter amount, choose method, optional reference and notes.</li><li><strong>Add Credit</strong> — opens a modal. Enter amount and a required reason. Credits offset future invoices.</li></ul><h3 id="invoices-table" tabindex="-1">Invoices table <a class="header-anchor" href="#invoices-table" aria-label="Permalink to &quot;Invoices table&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Column</th><th>Notes</th></tr></thead><tbody><tr><td><strong>Invoice #</strong></td><td>Monospace.</td></tr><tr><td><strong>Plan</strong></td><td>Display + version.</td></tr><tr><td><strong>Period</strong></td><td>Date range, monospace.</td></tr><tr><td><strong>Subtotal / Tax / Credits / Total</strong></td><td>Currency, monospace.</td></tr><tr><td><strong>Status</strong></td><td>Draft / Issued / Paid / Overdue / Void.</td></tr><tr><td><strong>Issued</strong></td><td>Date issued.</td></tr><tr><td><strong>Due</strong></td><td>Due date. Red if overdue.</td></tr></tbody></table><p>Overdue rows have a red background.</p><h3 id="payments-table" tabindex="-1">Payments table <a class="header-anchor" href="#payments-table" aria-label="Permalink to &quot;Payments table&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Column</th><th>Notes</th></tr></thead><tbody><tr><td><strong>Invoice</strong></td><td>Linked invoice.</td></tr><tr><td><strong>Method</strong></td><td>Bank Transfer / Credit Card / Check / Wire / ACH / Other.</td></tr><tr><td><strong>Amount</strong></td><td>Currency, monospace.</td></tr><tr><td><strong>Status</strong></td><td>Pending / Processing / Completed / Failed.</td></tr><tr><td><strong>Reference</strong></td><td>Reference number.</td></tr><tr><td><strong>Processed</strong></td><td>Date processed.</td></tr></tbody></table><h3 id="credits-table" tabindex="-1">Credits table <a class="header-anchor" href="#credits-table" aria-label="Permalink to &quot;Credits table&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Column</th><th>Notes</th></tr></thead><tbody><tr><td><strong>Type</strong></td><td>Credit (green) / Debit (red) badge.</td></tr><tr><td><strong>Amount</strong></td><td>Currency, monospace. Coloured by type.</td></tr><tr><td><strong>Balance After</strong></td><td>Running balance after this entry.</td></tr><tr><td><strong>Note</strong></td><td>The reason you entered.</td></tr><tr><td><strong>Date</strong></td><td>When applied.</td></tr></tbody></table><p>Credits scroll infinitely.</p><h2 id="billing-setup-tab" tabindex="-1">Billing Setup tab <a class="header-anchor" href="#billing-setup-tab" aria-label="Permalink to &quot;Billing Setup tab&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">Screenshot</p><p><em>Billing Setup tab — Non-Production sections:</em> the Non-Production Billing section with &quot;Based on usage&quot; selected and Environment Defaults visible, plus the Non-Production Tenants table showing at least one tenant with a manual-override asterisk.</p></div><p>The configuration that drives all the numbers on the Overview tab.</p><h3 id="plan-billing-settings" tabindex="-1">Plan &amp; Billing Settings <a class="header-anchor" href="#plan-billing-settings" aria-label="Permalink to &quot;Plan &amp; Billing Settings&quot;">​</a></h3><ul><li><strong>Plan</strong> — display name and version. A <strong>Change</strong> button opens a modal to switch plans (warns that the change applies to the <em>next</em> invoice, no proration).</li><li><strong>Billing Interval</strong> — read-only, fixed by the plan.</li><li><strong>Tax Rate (%)</strong> — number input.</li><li><strong>Payment Mode</strong> — Offline / Online.</li></ul><h3 id="production-billing" tabindex="-1">Production Billing <a class="header-anchor" href="#production-billing" aria-label="Permalink to &quot;Production Billing&quot;">​</a></h3><p>Visible for non-perpetual plans.</p><ul><li><strong>Production Environments</strong> — multi-select chips. Tenants in these environments are billed at 100% against the plan. Add or remove with the chip controls.</li><li><strong>Plan Meters</strong> — read-only table showing the plan&#39;s included limits and overage pricing.</li></ul><h3 id="non-production-billing" tabindex="-1">Non-Production Billing <a class="header-anchor" href="#non-production-billing" aria-label="Permalink to &quot;Non-Production Billing&quot;">​</a></h3><p>Visible for non-perpetual plans. Pick a <strong>Billing Type</strong>:</p><table tabindex="0"><thead><tr><th>Type</th><th>Effect</th></tr></thead><tbody><tr><td><strong>Free</strong></td><td>Non-prod tenants are not billed.</td></tr><tr><td><strong>% of usage</strong></td><td>Bill non-prod usage at a percentage of the calculated value.</td></tr><tr><td><strong>Fixed monthly</strong></td><td>Bill non-prod as a flat monthly amount.</td></tr><tr><td><strong>Based on usage</strong></td><td>Compute non-prod bills using per-environment multipliers (e.g. DEV at 25%, UAT at 50%).</td></tr></tbody></table><p>For <strong>Based on usage</strong>, an <strong>Environment Defaults</strong> section appears — a list of environment / multiplier rows you can add and remove.</p><h3 id="non-production-tenants-table" tabindex="-1">Non-Production Tenants table <a class="header-anchor" href="#non-production-tenants-table" aria-label="Permalink to &quot;Non-Production Tenants table&quot;">​</a></h3><p>Visible for non-perpetual plans.</p><table tabindex="0"><thead><tr><th>Column</th><th>Notes</th></tr></thead><tbody><tr><td><strong>Tenant name</strong></td><td>A warning asterisk indicates the tenant has manual overrides.</td></tr><tr><td><strong>Env</strong></td><td>Environment badge.</td></tr><tr><td><strong>Multiplier</strong></td><td>Percentage, monospace.</td></tr><tr><td><strong>Meter Overrides</strong></td><td>Count of overrides, or <code>—</code>.</td></tr><tr><td><strong>Actions</strong></td><td>Edit.</td></tr></tbody></table><p>Click <strong>Edit</strong> on a tenant to open the override modal. You can:</p><ul><li>Change the <strong>Multiplier</strong> for this tenant.</li><li>Set <strong>per-meter overrides</strong> — multiplier, exclude from billing, or unit price override.</li><li>Adjust <strong>contract terms</strong> (free-form).</li><li>Click <strong>Reset to env default</strong> to drop overrides and inherit from the environment default.</li></ul><p><strong>Manually overridden tenants are not affected by changes to the environment default.</strong> Their values are pinned until you reset them.</p><h3 id="save" tabindex="-1">Save <a class="header-anchor" href="#save" aria-label="Permalink to &quot;Save&quot;">​</a></h3><p>A single <strong>Save Billing Settings</strong> button at the bottom of the page persists every change on the tab.</p><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li>The billing multiplier is stored as a 0–1 scale but displayed as a percentage (0.5 = &quot;50% billed&quot;).</li><li>Per-meter overrides only apply to meters that are part of the plan.</li><li>Perpetual plans hide non-production and environment configuration entirely — those plans have no metering.</li><li>The Overview tab and the Billing Setup tab share the same customer; switching between them does not lose unsaved Setup edits, but reloading the page does.</li></ul>',41)])])}const p=e(r,[["render",i]]);export{c as __pageData,p as default};
